import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { AnalyticsQuery, DashboardData, MetricType, TimeRange } from '../../src/models/analytics.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

// ─── Helpers ──────────────────────────────────────────────────────────

function makeOrder(overrides: Partial<Order> & { id: string }): Order {
  return {
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 100 }],
    total: 100,
    status: 'pending',
    createdAt: new Date('2024-06-15T12:00:00Z'),
    updatedAt: new Date('2024-06-15T12:00:00Z'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: `${overrides.id}@example.com`,
    role: 'member',
    createdAt: new Date('2024-06-15T12:00:00Z'),
    updatedAt: new Date('2024-06-15T12:00:00Z'),
    ...overrides,
  };
}

// Fixed range covering June 2024
const JUNE_RANGE: TimeRange = {
  start: new Date('2024-06-01T00:00:00Z'),
  end: new Date('2024-07-01T00:00:00Z'),
};

// Previous period: May 2024
const MAY_RANGE: TimeRange = {
  start: new Date('2024-05-01T00:00:00Z'),
  end: new Date('2024-06-01T00:00:00Z'),
};

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // ─── getDashboard ───────────────────────────────────────────────

  describe('getDashboard', () => {
    it('should return a dashboard with all sections populated', async () => {
      const query: AnalyticsQuery = { preset: '7d' };
      const result: DashboardData = await service.getDashboard(query);

      expect(result.metrics).toHaveLength(4);
      expect(result.metrics.map((m) => m.type)).toEqual([
        'revenue',
        'orders',
        'users',
        'conversion',
      ]);
      expect(result.ordersByStatus).toBeDefined();
      expect(result.topProducts).toBeDefined();
      expect(result.generatedAt).toBeInstanceOf(Date);
    });

    it('should accept a custom time range', async () => {
      const query: AnalyticsQuery = {
        range: {
          start: new Date('2024-01-01'),
          end: new Date('2024-01-31'),
        },
      };
      const result = await service.getDashboard(query);

      expect(result.query.range).toBeDefined();
      expect(result.query.range?.start).toEqual(new Date('2024-01-01'));
    });

    it('should default to 7d when no preset or range given', async () => {
      const result = await service.getDashboard({});
      expect(result.query.range).toBeDefined();
    });

    it('should aggregate real data across all dashboard sections', async () => {
      // Seed data in June
      orderRepo.save(makeOrder({ id: 'o1', total: 200, status: 'pending', createdAt: new Date('2024-06-10T10:00:00Z'), items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 100 }] }));
      orderRepo.save(makeOrder({ id: 'o2', total: 50, status: 'delivered', createdAt: new Date('2024-06-20T10:00:00Z'), items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 50 }] }));
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2024-06-05T10:00:00Z') }));

      const result = await service.getDashboard({ range: JUNE_RANGE });

      // Revenue metric
      const revenue = result.metrics.find((m) => m.type === 'revenue')!;
      expect(revenue.current).toBe(250);

      // Orders metric
      const orders = result.metrics.find((m) => m.type === 'orders')!;
      expect(orders.current).toBe(2);

      // Users metric
      const users = result.metrics.find((m) => m.type === 'users')!;
      expect(users.current).toBe(1);

      // Status breakdown
      expect(result.ordersByStatus.pending).toBe(1);
      expect(result.ordersByStatus.delivered).toBe(1);

      // Top products
      expect(result.topProducts).toHaveLength(2);
      expect(result.topProducts[0].productId).toBe('p1'); // higher revenue
    });
  });

  // ─── getMetric ──────────────────────────────────────────────────

  describe('getMetric', () => {
    it('should return a metric summary for each valid type', async () => {
      const types: MetricType[] = ['revenue', 'orders', 'users', 'conversion'];

      for (const type of types) {
        const result = await service.getMetric(type, { preset: '7d' });

        expect(result.type).toBe(type);
        expect(result).toHaveProperty('current');
        expect(result).toHaveProperty('previous');
        expect(result).toHaveProperty('changePercent');
        expect(result).toHaveProperty('series');
      }
    });

    it('should compute revenue correctly', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2024-06-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, createdAt: new Date('2024-06-15T10:00:00Z') }));

      const result = await service.getMetric('revenue', { range: JUNE_RANGE });
      expect(result.current).toBe(300);
    });

    it('should compute order count correctly', async () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2024-06-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2024-06-15T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2024-06-20T10:00:00Z') }));

      const result = await service.getMetric('orders', { range: JUNE_RANGE });
      expect(result.current).toBe(3);
    });

    it('should compute user count correctly', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2024-06-05T10:00:00Z') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2024-06-15T10:00:00Z') }));

      const result = await service.getMetric('users', { range: JUNE_RANGE });
      expect(result.current).toBe(2);
    });

    it('should compute conversion rate correctly', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2024-06-05T10:00:00Z') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2024-06-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2024-06-10T10:00:00Z') }));

      const result = await service.getMetric('conversion', { range: JUNE_RANGE });
      // 1 order / 2 users = 0.5
      expect(result.current).toBe(0.5);
    });

    it('should compute changePercent from previous period', async () => {
      // May (previous period): 1 order worth $100
      orderRepo.save(makeOrder({ id: 'o-may', total: 100, createdAt: new Date('2024-05-15T10:00:00Z') }));
      // June (current period): 1 order worth $200
      orderRepo.save(makeOrder({ id: 'o-jun', total: 200, createdAt: new Date('2024-06-15T10:00:00Z') }));

      const result = await service.getMetric('revenue', { range: JUNE_RANGE });
      expect(result.current).toBe(200);
      expect(result.previous).toBe(100);
      expect(result.changePercent).toBe(100); // 100% increase
    });

    it('should return 0 changePercent when previous period is empty', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 500, createdAt: new Date('2024-06-15T10:00:00Z') }));

      const result = await service.getMetric('revenue', { range: JUNE_RANGE });
      expect(result.current).toBe(500);
      expect(result.previous).toBe(0);
      expect(result.changePercent).toBe(0);
    });

    it('should include time series data points', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2024-06-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', total: 50, createdAt: new Date('2024-06-10T14:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o3', total: 200, createdAt: new Date('2024-06-15T10:00:00Z') }));

      const result = await service.getMetric('revenue', { range: JUNE_RANGE });

      // Should have a data point for each day in June
      expect(result.series.length).toBe(30); // June has 30 days

      // Find the June 10th bucket
      const june10 = result.series.find((p) => p.label === '2024-06-10');
      expect(june10).toBeDefined();
      expect(june10!.value).toBe(150); // 100 + 50

      const june15 = result.series.find((p) => p.label === '2024-06-15');
      expect(june15).toBeDefined();
      expect(june15!.value).toBe(200);

      // Days with no orders should be 0
      const june01 = result.series.find((p) => p.label === '2024-06-01');
      expect(june01).toBeDefined();
      expect(june01!.value).toBe(0);
    });
  });

  // ─── getOrderStatusBreakdown ────────────────────────────────────

  describe('getOrderStatusBreakdown', () => {
    it('should return counts for all statuses', async () => {
      const result = await service.getOrderStatusBreakdown(JUNE_RANGE);

      expect(result).toHaveProperty('pending');
      expect(result).toHaveProperty('confirmed');
      expect(result).toHaveProperty('shipped');
      expect(result).toHaveProperty('delivered');
      expect(result).toHaveProperty('cancelled');
    });

    it('should return all zeros when no orders exist', async () => {
      const result = await service.getOrderStatusBreakdown(JUNE_RANGE);

      expect(result.pending).toBe(0);
      expect(result.confirmed).toBe(0);
      expect(result.shipped).toBe(0);
      expect(result.delivered).toBe(0);
      expect(result.cancelled).toBe(0);
    });

    it('should correctly count orders by status', async () => {
      orderRepo.save(makeOrder({ id: 'o1', status: 'pending', createdAt: new Date('2024-06-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', status: 'pending', createdAt: new Date('2024-06-11T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o3', status: 'confirmed', createdAt: new Date('2024-06-12T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o4', status: 'shipped', createdAt: new Date('2024-06-13T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o5', status: 'delivered', createdAt: new Date('2024-06-14T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o6', status: 'cancelled', createdAt: new Date('2024-06-15T10:00:00Z') }));

      const result = await service.getOrderStatusBreakdown(JUNE_RANGE);

      expect(result.pending).toBe(2);
      expect(result.confirmed).toBe(1);
      expect(result.shipped).toBe(1);
      expect(result.delivered).toBe(1);
      expect(result.cancelled).toBe(1);
    });

    it('should only count orders within the time range', async () => {
      orderRepo.save(makeOrder({ id: 'o1', status: 'pending', createdAt: new Date('2024-06-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', status: 'pending', createdAt: new Date('2024-05-10T10:00:00Z') })); // outside range
      orderRepo.save(makeOrder({ id: 'o3', status: 'pending', createdAt: new Date('2024-07-01T00:00:00Z') })); // at exclusive end

      const result = await service.getOrderStatusBreakdown(JUNE_RANGE);
      expect(result.pending).toBe(1);
    });
  });

  // ─── getTopProducts ─────────────────────────────────────────────

  describe('getTopProducts', () => {
    it('should return an empty array when no orders exist', async () => {
      const result = await service.getTopProducts(JUNE_RANGE);
      expect(result).toEqual([]);
    });

    it('should aggregate revenue across multiple orders for the same product', async () => {
      orderRepo.save(makeOrder({
        id: 'o1',
        createdAt: new Date('2024-06-10T10:00:00Z'),
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 100 }],
      }));
      orderRepo.save(makeOrder({
        id: 'o2',
        createdAt: new Date('2024-06-15T10:00:00Z'),
        items: [{ productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 100 }],
      }));

      const result = await service.getTopProducts(JUNE_RANGE);

      expect(result).toHaveLength(1);
      expect(result[0].productId).toBe('p1');
      expect(result[0].totalRevenue).toBe(500); // (2*100) + (3*100)
      expect(result[0].totalQuantity).toBe(5);
    });

    it('should sort products by revenue descending', async () => {
      orderRepo.save(makeOrder({
        id: 'o1',
        createdAt: new Date('2024-06-10T10:00:00Z'),
        items: [
          { productId: 'p1', name: 'Cheap', quantity: 10, unitPrice: 1 },
          { productId: 'p2', name: 'Expensive', quantity: 1, unitPrice: 1000 },
        ],
      }));

      const result = await service.getTopProducts(JUNE_RANGE);

      expect(result).toHaveLength(2);
      expect(result[0].productId).toBe('p2'); // $1000
      expect(result[1].productId).toBe('p1'); // $10
    });

    it('should respect the limit parameter', async () => {
      orderRepo.save(makeOrder({
        id: 'o1',
        createdAt: new Date('2024-06-10T10:00:00Z'),
        items: [
          { productId: 'p1', name: 'A', quantity: 1, unitPrice: 300 },
          { productId: 'p2', name: 'B', quantity: 1, unitPrice: 200 },
          { productId: 'p3', name: 'C', quantity: 1, unitPrice: 100 },
        ],
      }));

      const result = await service.getTopProducts(JUNE_RANGE, 2);
      expect(result).toHaveLength(2);
      expect(result[0].productId).toBe('p1');
      expect(result[1].productId).toBe('p2');
    });

    it('should only count orders within the time range', async () => {
      orderRepo.save(makeOrder({
        id: 'o1',
        createdAt: new Date('2024-06-10T10:00:00Z'),
        items: [{ productId: 'p1', name: 'In-Range', quantity: 1, unitPrice: 50 }],
      }));
      orderRepo.save(makeOrder({
        id: 'o2',
        createdAt: new Date('2024-05-01T10:00:00Z'), // outside range
        items: [{ productId: 'p2', name: 'Out-Of-Range', quantity: 1, unitPrice: 999 }],
      }));

      const result = await service.getTopProducts(JUNE_RANGE);
      expect(result).toHaveLength(1);
      expect(result[0].productId).toBe('p1');
    });
  });

  // ─── Edge cases ─────────────────────────────────────────────────

  describe('edge cases', () => {
    it('should handle empty data gracefully for all metrics', async () => {
      const result = await service.getDashboard({ range: JUNE_RANGE });

      for (const metric of result.metrics) {
        expect(metric.current).toBe(0);
        expect(metric.previous).toBe(0);
        expect(metric.changePercent).toBe(0);
      }
      expect(result.topProducts).toEqual([]);
    });

    it('should handle a single data point', async () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 42, createdAt: new Date('2024-06-15T10:00:00Z') }));

      const result = await service.getMetric('revenue', { range: JUNE_RANGE });
      expect(result.current).toBe(42);
    });

    it('should handle orders at the exact start boundary (inclusive)', async () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2024-06-01T00:00:00Z') }));

      const result = await service.getMetric('orders', { range: JUNE_RANGE });
      expect(result.current).toBe(1);
    });

    it('should exclude orders at the exact end boundary (exclusive)', async () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2024-07-01T00:00:00Z') }));

      const result = await service.getMetric('orders', { range: JUNE_RANGE });
      expect(result.current).toBe(0);
    });

    it('should handle a narrow 1-day range', async () => {
      const range: TimeRange = {
        start: new Date('2024-06-15T00:00:00Z'),
        end: new Date('2024-06-16T00:00:00Z'),
      };
      orderRepo.save(makeOrder({ id: 'o1', total: 10, createdAt: new Date('2024-06-15T12:00:00Z') }));

      const result = await service.getMetric('revenue', { range });
      expect(result.current).toBe(10);
      expect(result.series).toHaveLength(1);
      expect(result.series[0].label).toBe('2024-06-15');
    });

    it('should handle a large number of orders', async () => {
      for (let i = 0; i < 100; i++) {
        const day = String(1 + (i % 28)).padStart(2, '0');
        orderRepo.save(makeOrder({
          id: `o${i}`,
          total: 10,
          createdAt: new Date(`2024-06-${day}T12:00:00Z`),
        }));
      }

      const result = await service.getMetric('revenue', { range: JUNE_RANGE });
      expect(result.current).toBe(1000); // 100 * 10
    });

    it('should handle conversion with zero users', async () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2024-06-10T10:00:00Z') }));

      const result = await service.getMetric('conversion', { range: JUNE_RANGE });
      expect(result.current).toBe(0); // 0 users => 0 conversion
    });

    it('should handle conversion with zero orders but some users', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2024-06-10T10:00:00Z') }));

      const result = await service.getMetric('conversion', { range: JUNE_RANGE });
      expect(result.current).toBe(0); // 0 orders / 1 user = 0
    });

    it('should use preset 24h correctly', async () => {
      // Seed an order within the last 24h by using a query relative to now
      const result = await service.getMetric('orders', { preset: '24h' });
      expect(result.series.length).toBeGreaterThanOrEqual(1);
    });

    it('should use preset 30d correctly', async () => {
      const result = await service.getMetric('orders', { preset: '30d' });
      expect(result.series.length).toBe(30);
    });

    it('should use preset 90d correctly', async () => {
      const result = await service.getMetric('orders', { preset: '90d' });
      expect(result.series.length).toBe(90);
    });

    it('should prefer custom range over preset', async () => {
      const query: AnalyticsQuery = {
        preset: '7d',
        range: JUNE_RANGE,
      };
      const result = await service.getMetric('revenue', query);
      // Should use the custom range (30 days in June)
      expect(result.series.length).toBe(30);
    });
  });

  // ─── Time series details ────────────────────────────────────────

  describe('time series', () => {
    it('should build correct order count series', async () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2024-06-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2024-06-10T15:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2024-06-11T10:00:00Z') }));

      const result = await service.getMetric('orders', { range: JUNE_RANGE });

      const june10 = result.series.find((p) => p.label === '2024-06-10');
      expect(june10!.value).toBe(2);

      const june11 = result.series.find((p) => p.label === '2024-06-11');
      expect(june11!.value).toBe(1);
    });

    it('should build correct user count series', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2024-06-05T10:00:00Z') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2024-06-05T15:00:00Z') }));
      userRepo.save(makeUser({ id: 'u3', createdAt: new Date('2024-06-20T10:00:00Z') }));

      const result = await service.getMetric('users', { range: JUNE_RANGE });

      const june5 = result.series.find((p) => p.label === '2024-06-05');
      expect(june5!.value).toBe(2);

      const june20 = result.series.find((p) => p.label === '2024-06-20');
      expect(june20!.value).toBe(1);
    });

    it('should build correct conversion series', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2024-06-10T10:00:00Z') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2024-06-10T12:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2024-06-10T10:00:00Z') }));

      const result = await service.getMetric('conversion', { range: JUNE_RANGE });

      const june10 = result.series.find((p) => p.label === '2024-06-10');
      expect(june10!.value).toBe(0.5); // 1 order / 2 users

      // Days with no users should have 0 conversion
      const june01 = result.series.find((p) => p.label === '2024-06-01');
      expect(june01!.value).toBe(0);
    });

    it('should have timestamps as Date objects in series', async () => {
      const result = await service.getMetric('revenue', { range: JUNE_RANGE });
      for (const point of result.series) {
        expect(point.timestamp).toBeInstanceOf(Date);
      }
    });
  });

  // ─── Previous period comparison ─────────────────────────────────

  describe('previous period comparison', () => {
    it('should compute negative change when current < previous', async () => {
      // May: $300
      orderRepo.save(makeOrder({ id: 'o-may', total: 300, createdAt: new Date('2024-05-15T10:00:00Z') }));
      // June: $100
      orderRepo.save(makeOrder({ id: 'o-jun', total: 100, createdAt: new Date('2024-06-15T10:00:00Z') }));

      const result = await service.getMetric('revenue', { range: JUNE_RANGE });
      expect(result.changePercent).toBeCloseTo(-66.67, 1); // (100-300)/300 * 100
    });

    it('should compute 0% change when current equals previous', async () => {
      orderRepo.save(makeOrder({ id: 'o-may', total: 100, createdAt: new Date('2024-05-15T10:00:00Z') }));
      orderRepo.save(makeOrder({ id: 'o-jun', total: 100, createdAt: new Date('2024-06-15T10:00:00Z') }));

      const result = await service.getMetric('revenue', { range: JUNE_RANGE });
      expect(result.changePercent).toBe(0);
    });
  });
});

